(1156, '2.4.42-110', '2.4.42-110.png', '', '', 2, 0, 0, 0, ',61,1001,', ',19,6,', 'Welches Dokument erlaubt es Ihnen, hier zu parken?'),
(1157, '2.5.01-130', '', '', '', 3, 0, 0, 0, ',99,', ',19,6,', 'Sie fahren einen Pkw mit der Antriebsart Plug-in-Hybrid. Wie können Sie den Kraftstoffverbrauch optimieren?'),
(1158, '2.6.03-121', '', '', '', 3, 0, 0, 0, ',16,1008,', ',19,6,', 'Was kann die Fahrstabilität eines mitgeführten Anhängers beeinträchtigen?'),
(1159, '2.6.06-104', '', '', 'Ich muss', 3, 0, 0, 0, ',8,', ',19,6,7,8,9,20,12,21,13,', 'Was gilt beim Betrieb von Fahrzeugen hinsichtlich der Fahrzeughöhe einschließlich der Höhe der Ladung?'),
(1160, '2.7.01-167', '', '', '', 3, 0, 0, 0, ',40,1007,', ',19,6,7,8,10,11,', 'Was gilt bei der Nutzung von Fahrerassistenzsystemen für die Längs- und Querführung Ihres Kraftfahrzeugs?'),
(1161, '2.7.02-140', '', '', '', 2, 0, 0, 0, ',101,', ',19,6,', 'In Ihrem Pkw ist der Sicherheitsgurt für den Beifahrer defekt. Wie verhalten Sie sich richtig?'),
(1162, '1.4.40-013', '', '', '', 3, 1, 1, 0, ',42,1001,', '', 'Sie fahren auf einer Straße mit einem Fahrstreifen für jede Richtung. Bei welchem Verkehrszeichen müssen Sie dem Gegenverkehr grundsätzlich Vorrang gewähren?'),
